import type {
  FormatterWithPrecision,
  TimeFormatter,
} from '../../../types/formatter.js';

export const MARKER_VALUE_SEPARATOR = '–';

type MarkerFormatter = FormatterWithPrecision | TimeFormatter;

export function getMarkerValue(
  marker: { y0: number | Date; y1: number | Date },
  formatter: MarkerFormatter = (value: number | Date) => `${value}`,
) {
  return marker.y0 === marker.y1
    ? formatter(marker.y0 as number & Date)
    : `${formatter(
        marker.y0 as number & Date,
      )} ${MARKER_VALUE_SEPARATOR} ${formatter(marker.y1 as number & Date)}`;
}
